const now = new Date().toISOString();

const input = $input.first()?.json || {};
const context = input.context || {};

const client = context.client || {};
const trajet = context.trajet || {};
const distance = context.distance || {};
const devis = context.devis || {};
const pricing = context.pricing || {};

function escapeHtml(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function formatCurrency(value) {
  const number = Number(value || 0);
  return number.toLocaleString("fr-FR", {
    style: "currency",
    currency: devis.currency || "EUR"
  });
}

function formatDate(value) {
  if (!value) return "";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);

  return date.toLocaleDateString("fr-FR", {
    year: "numeric",
    month: "long",
    day: "numeric"
  });
}

const quoteId =
  devis.quote_id ||
  `DEVIS-${context.airtable?.demande_record_id || Date.now()}`;

const fileName = `${quoteId}.pdf`;

const clientDisplayName = [client.prenom, client.nom]
  .filter(Boolean)
  .join(" ")
  .trim() || client.nom || "Client";

const tvaPercent =
  devis.tva_pourcentage ??
  pricing.vat?.percent ??
  10;

const prixBaseHt =
  devis.prix_base_ht ??
  devis.base_ht ??
  devis.total_ht ??
  0;

const totalHt = devis.total_ht ?? 0;
const totalTtc = devis.total_ttc ?? 0;
const montantTva =
  devis.montant_tva ??
  Math.max(0, Number(totalTtc) - Number(totalHt));

const ajustements = Number(totalHt) - Number(prixBaseHt);

const html = `
<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8" />
  <title>Devis ${escapeHtml(quoteId)}</title>
  <style>
    @page { size: A4 portrait; margin: 10mm; }

    * {
      box-sizing: border-box;
    }

    body {
      font-family: Arial, Helvetica, sans-serif;
      margin: 0;
      color: #1f2937;
      background: #ffffff;
      font-size: 11px;
      line-height: 1.3;
    }

    .header {
      display: flex;
      justify-content: space-between;
      border-bottom: 3px solid #123C69;
      padding-bottom: 12px;
      margin-bottom: 16px;
    }

    .brand {
      font-size: 24px;
      font-weight: 700;
      color: #123C69;
    }

    .brand span {
      color: #4CAF50;
    }

    .subtitle {
      margin-top: 4px;
      color: #4b5563;
    }

    .quote-meta {
      text-align: right;
      color: #4b5563;
    }

    .quote-title {
      font-size: 22px;
      color: #123C69;
      margin: 0 0 6px 0;
      font-weight: 700;
    }

    .section {
      margin-bottom: 14px;
    }

    .section-title {
      background: #f0f7f4;
      color: #123C69;
      padding: 7px 10px;
      font-size: 13px;
      font-weight: 700;
      border-left: 4px solid #4CAF50;
      margin-bottom: 8px;
    }

    .grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 10px;
    }

    .card {
      border: 1px solid #e5e7eb;
      border-radius: 6px;
      padding: 9px;
      background: #ffffff;
    }

    .row {
      display: flex;
      justify-content: space-between;
      gap: 10px;
      padding: 4px 0;
      border-bottom: 1px solid #f3f4f6;
    }

    .row:last-child {
      border-bottom: none;
    }

    .label {
      color: #6b7280;
      font-weight: 600;
    }

    .value {
      color: #111827;
      text-align: right;
      font-weight: 500;
    }

    table {
      width: 100%;
      border-collapse: collapse;
      margin-top: 6px;
      font-size: 11px;
    }

    th {
      background: #123C69;
      color: #ffffff;
      text-align: left;
      padding: 7px 8px;
      font-weight: 700;
    }

    td {
      border-bottom: 1px solid #e5e7eb;
      padding: 7px 8px;
    }

    td.amount {
      text-align: right;
      font-weight: 600;
      white-space: nowrap;
    }

    .totals {
      width: 45%;
      margin-left: auto;
      margin-top: 10px;
      border: 1px solid #e5e7eb;
      border-radius: 6px;
      overflow: hidden;
    }

    .total-row {
      display: flex;
      justify-content: space-between;
      padding: 7px 10px;
      border-bottom: 1px solid #e5e7eb;
    }

    .total-final {
      background: #123C69;
      color: #ffffff;
      font-size: 14px;
      font-weight: 700;
    }

    .notice {
      margin-top: 12px;
      padding: 9px;
      background: #f9fafb;
      border-left: 4px solid #4CAF50;
      color: #374151;
      font-size: 10px;
    }

    .footer {
      margin-top: 14px;
      padding-top: 7px;
      border-top: 1px solid #e5e7eb;
      font-size: 9px;
      color: #6b7280;
      text-align: center;
    }
  </style>
</head>

<body>
  <div class="header">
    <div>
      <div class="brand">Neo<span>Travel</span></div>
      <div class="subtitle">Organisation de transport de groupe</div>
    </div>

    <div class="quote-meta">
      <h1 class="quote-title">Devis</h1>
      <div><strong>N° :</strong> ${escapeHtml(quoteId)}</div>
      <div><strong>Date :</strong> ${escapeHtml(formatDate(now))}</div>
      <div><strong>Statut :</strong> ${escapeHtml(devis.status || "Généré")}</div>
    </div>
  </div>

  <div class="section">
    <div class="section-title">Client</div>
    <div class="card">
      <div class="row">
        <div class="label">Nom</div>
        <div class="value">${escapeHtml(clientDisplayName)}</div>
      </div>
      <div class="row">
        <div class="label">Email</div>
        <div class="value">${escapeHtml(client.email || "")}</div>
      </div>
      <div class="row">
        <div class="label">Téléphone</div>
        <div class="value">${escapeHtml(client.telephone || "Non renseigné")}</div>
      </div>
    </div>
  </div>

  <div class="section">
    <div class="section-title">Trajet</div>
    <div class="grid">
      <div class="card">
        <div class="row">
          <div class="label">Départ</div>
          <div class="value">${escapeHtml(trajet.depart || "")}</div>
        </div>
        <div class="row">
          <div class="label">Destination</div>
          <div class="value">${escapeHtml(trajet.destination || "")}</div>
        </div>
        <div class="row">
          <div class="label">Date départ</div>
          <div class="value">${escapeHtml(formatDate(trajet.date_depart))}</div>
        </div>
      </div>

      <div class="card">
        <div class="row">
          <div class="label">Type</div>
          <div class="value">${escapeHtml(trajet.type_trajet || "Transport groupe")}</div>
        </div>
        <div class="row">
          <div class="label">Passagers</div>
          <div class="value">${escapeHtml(trajet.nb_passagers || "")}</div>
        </div>
        <div class="row">
          <div class="label">Distance</div>
          <div class="value">${escapeHtml(distance.distance_km || "")} km</div>
        </div>
      </div>
    </div>
  </div>

  <div class="section">
    <div class="section-title">Détail du devis</div>

    <table>
      <thead>
        <tr>
          <th>Description</th>
          <th style="text-align:right;">Montant HT</th>
        </tr>
      </thead>
      <tbody>
        <tr>
          <td>${escapeHtml(devis.formule_utilisee || "Base transport")}</td>
          <td class="amount">${formatCurrency(prixBaseHt)}</td>
        </tr>
        <tr>
          <td>Ajustements tarifaires, saisonnalité, capacité, options et marge commerciale</td>
          <td class="amount">${formatCurrency(ajustements)}</td>
        </tr>
      </tbody>
    </table>

    <div class="totals">
      <div class="total-row">
        <div>Total HT</div>
        <div>${formatCurrency(totalHt)}</div>
      </div>
      <div class="total-row">
        <div>TVA ${escapeHtml(tvaPercent)}%</div>
        <div>${formatCurrency(montantTva)}</div>
      </div>
      <div class="total-row total-final">
        <div>Total TTC</div>
        <div>${formatCurrency(totalTtc)}</div>
      </div>
    </div>
  </div>

  <div class="notice">
    Ce devis est établi sur la base des informations transmises.
    Il reste soumis à disponibilité partenaire et validation commerciale.
  </div>

  <div class="footer">
    NeoTravel — Devis généré automatiquement — ${escapeHtml(quoteId)}
  </div>
</body>
</html>
`;

const updatedContext = {
  ...context,
  devis: {
    ...devis,
    quote_id: quoteId
  },
  pdf: {
    ...(context.pdf || {}),
    html_created: true,
    html_created_at: now,
    filename: fileName,
    quote_id: quoteId
  },
  last_update_at: now
};

return [
  {
    json: {
      success: true,
      message: "HTML du devis généré.",
      context: updatedContext,
      html,
      result: {
        entity: "pdf",
        filename: fileName,
        quote_id: quoteId
      }
    }
  }
];

const now = new Date().toISOString();

const input = $input.first()?.json || {};
const context = JSON.parse(JSON.stringify(input.context || {}));
const html = input.html || "";

if (!html) {
  return [
    {
      json: {
        success: false,
        message: "Impossible de générer le PDF : HTML manquant.",
        context,
        result: {
          entity: "pdf",
          errors: ["html manquant"]
        }
      }
    }
  ];
}

const quoteId =
  context.devis?.quote_id ||
  context.pdf?.quote_id ||
  `DEVIS-${context.airtable?.demande_record_id || Date.now()}`;

const htmlFilename = "index.html";
const pdfFilename = `${quoteId}.pdf`;

context.pdf = {
  ...(context.pdf || {}),
  html_ready: true,
  html_filename: htmlFilename,
  filename: pdfFilename,
  quote_id: quoteId,
  engine: "gotenberg",
  gotenberg: {
    endpoint: "http://gotenberg:3000/forms/chromium/convert/html",
    options: {
      paperSize: "A4",
      marginTop: "10mm",
      marginBottom: "10mm",
      marginLeft: "10mm",
      marginRight: "10mm",
      printBackground: "true",
      landscape: "false",
      scale: "1"
    }
  },
  prepared_at: now
};

const binary = await this.helpers.prepareBinaryData(
  Buffer.from(html, "utf8"),
  htmlFilename,
  "text/html"
);

return [
  {
    json: {
      success: true,
      message: "HTML prêt pour conversion PDF.",
      context,
      result: {
        entity: "pdf",
        filename: pdfFilename,
        quote_id: quoteId
      }
    },
    binary: {
      data: binary
    }
  }
];

const now = new Date().toISOString();

const input = $input.first();
const json = input.json || {};
const binary = input.binary || {};

const context = JSON.parse(JSON.stringify(json.context || {}));
const pdfBinary = binary.pdf || null;

const errors = [];

if (!pdfBinary) {
  errors.push("binary.pdf manquant");
}

if (pdfBinary && pdfBinary.mimeType !== "application/pdf") {
  errors.push(`mimeType invalide : ${pdfBinary.mimeType || "inconnu"}`);
}

if (pdfBinary && Number(pdfBinary.fileSize || 0) <= 0) {
  errors.push("PDF vide");
}

if (errors.length > 0) {
  context.pdf = {
    ...(context.pdf || {}),
    generated: false,
    error: "PDF_GENERATION_FAILED",
    errors,
    checked_at: now
  };

  return [
    {
      json: {
        success: false,
        message: "Impossible de générer le devis PDF.",
        context,
        result: {
          entity: "pdf",
          errors
        }
      },
      binary
    }
  ];
}

const quoteId =
  context.devis?.quote_id ||
  context.pdf?.quote_id ||
  `DEVIS-${context.airtable?.demande_record_id || Date.now()}`;

const pdfFilename = `${quoteId}.pdf`;

context.pdf = {
  ...(context.pdf || {}),
  generated: true,
  generated_at: now,
  filename: pdfFilename,
  engine_filename: pdfBinary.fileName || null,
  mime_type: pdfBinary.mimeType || null,
  size: pdfBinary.fileSize || null,
  engine: context.pdf?.engine || "gotenberg",
  checked_at: now
};

return [
  {
    json: {
      success: true,
      message: "PDF généré avec succès.",
      context,
      result: {
        entity: "pdf",
        filename: pdfFilename,
        quote_id: quoteId
      }
    },
    binary: {
      pdf: pdfBinary
    }
  }
];

// =======================================
// WF_008_Generate_PDF
// Retour du Tool
// Version : 3.0
// Contrat de sortie standard NeoTravel
// =======================================

const now = new Date().toISOString();

const input = $input.first()?.json || {};
const context = input.context || {};

// =======================================
// Erreur
// =======================================

if (input.success !== true) {

  return [
    {
      json: {

        success: false,

        status: "ERROR",

        tool: "WF_008_Generate_PDF",

        version: "3.0",

        timestamp: now,

        context,

        message: input.message || "Impossible de générer le devis PDF.",

        next_action: "error",

        next_workflow: "",

        next_payload: {},

        error: {
          code: "PDF_GENERATION_ERROR",
          details: input.message || "Erreur lors de la génération du PDF."
        }

      }
    }
  ];

}

// =======================================
// Succès
// =======================================

return [
  {
    json: {

      success: true,

      status: "PDF_GENERATED",

      tool: "WF_008_Generate_PDF",

      version: "3.0",

      timestamp: now,

      context,

      message: "Le devis PDF a été généré avec succès.",

      next_action: "call_tool",

      next_workflow: "WF_010_Send_Email",

      next_payload: {

        context,

        email_type: "COMMERCIAL_VALIDATION",

        reason: "Devis PDF généré automatiquement. Validation commerciale requise avant envoi au client."

      },

      error: null

    }
  }
];

const now = new Date().toISOString();

const airtableResult = $input.first()?.json || {};

let previous = {};
let drive = {};

try {
  previous = $("Check_PDF_Result").first().json || {};
} catch (e) {
  previous = {};
}

try {
  drive = $("Upload file").first().json || {};
} catch (e) {
  drive = {};
}

const context = JSON.parse(JSON.stringify(previous.context || {}));

const success = !!airtableResult.id;

if (!success) {
  context.pdf = {
    ...(context.pdf || {}),
    saved_to_airtable: false,
    error: "AIRTABLE_UPDATE_FAILED",
    checked_at: now
  };

  context.last_update_at = now;

  return [
    {
      json: {
        success: false,
        message: "Le PDF a été généré mais la mise à jour Airtable a échoué.",
        context,
        result: {
          entity: "pdf",
          errors: ["AIRTABLE_UPDATE_FAILED"]
        }
      }
    }
  ];
}

context.pdf = {
  ...(context.pdf || {}),
  saved_to_drive: !!drive.id,
  saved_to_airtable: true,
  saved_to_airtable_at: now,
  drive_file_id: drive.id || null,
  drive_filename: drive.name || context.pdf?.filename || null,
  drive_view_url: drive.webViewLink || null,
  drive_download_url: drive.webContentLink || null,
  airtable_record_id: airtableResult.id,
  airtable_fields: airtableResult.fields || {}
};

context.last_update_at = now;

return [
  {
    json: {
      success: true,
      message: "PDF généré, envoyé sur Drive et enregistré dans Airtable.",
      context,
      result: {
        entity: "pdf",
        pdf_url: context.pdf.drive_view_url,
        drive_file_id: context.pdf.drive_file_id
      }
    }
  }
];

const now = new Date().toISOString();

const input = $input.first()?.json || {};
const context = input.context || {};

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function isEmpty(value) {
  return (
    value === undefined ||
    value === null ||
    value === "" ||
    String(value).trim() === ""
  );
}

const errors = [];

if (!isObject(context)) {
  errors.push("context manquant ou invalide");
}

if (isEmpty(context.airtable?.demande_record_id)) {
  errors.push("context.airtable.demande_record_id manquant");
}

if (isEmpty(context.devis?.airtable_record_id)) {
  errors.push("context.devis.airtable_record_id manquant");
}

if (!isObject(context.client)) {
  errors.push("context.client manquant");
}

if (!isObject(context.trajet)) {
  errors.push("context.trajet manquant");
}

if (!isObject(context.devis)) {
  errors.push("context.devis manquant");
}

if (isEmpty(context.client?.nom)) {
  errors.push("context.client.nom manquant");
}

if (isEmpty(context.client?.email)) {
  errors.push("context.client.email manquant");
}

if (isEmpty(context.trajet?.depart)) {
  errors.push("context.trajet.depart manquant");
}

if (isEmpty(context.trajet?.destination)) {
  errors.push("context.trajet.destination manquant");
}

if (isEmpty(context.trajet?.date_depart)) {
  errors.push("context.trajet.date_depart manquant");
}

if (isEmpty(context.trajet?.nb_passagers)) {
  errors.push("context.trajet.nb_passagers manquant");
}

if (isEmpty(context.devis?.total_ht)) {
  errors.push("context.devis.total_ht manquant");
}

if (isEmpty(context.devis?.total_ttc)) {
  errors.push("context.devis.total_ttc manquant");
}

if (errors.length > 0) {
  return [
    {
      json: {
        success: false,
        message: "Impossible de générer le devis PDF : données manquantes.",
        context,
        result: {
          entity: "pdf",
          errors
        }
      }
    }
  ];
}

const quoteId =
  context.devis?.quote_id ||
  `DEVIS-${context.airtable.demande_record_id}`;

const updatedContext = {
  ...context,
  devis: {
    ...context.devis,
    quote_id: quoteId
  },
  pdf: {
    ...(context.pdf || {}),
    generation_started_at: now,
    generated: false
  },
  last_update_at: now
};

return [
  {
    json: {
      success: true,
      message: "Contexte validé pour génération PDF.",
      context: updatedContext,
      result: {
        entity: "pdf"
      }
    }
  }
];
